  1→import { createPanel } from '../../domain/partModels';
  2→import { createConstraint } from '../../domain/constraintModels';
  3→import { computeExtrusionFromFace } from '../../domain/extrusion';
  4→import { identifyFace } from '../../domain/drawingPlane';
  5→import { snapToGrid } from '../snap';
  6→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  7→
  8→/**
  9→ * Push/pull extrusion handler.
 10→ * Click a face and drag outward to create a new part attached to that face.
 11→ * Type a number + Enter for exact distance.
 12→ */
 13→export function createPushPullHandler3d({ dispatch, editorDispatch, project, snapEnabled }) {
 14→  return {
 15→    onPointerDown(intersection, e, toolState, viewport) {
 16→      if (e.button !== 0) return;
 17→
 18→      if (!intersection || !intersection.partId || !intersection.faceNormal) {
 19→        editorDispatch({
 20→          type: 'UPDATE_TOOL_STATE',
 21→          payload: { extruding: false, sourcePart: null, faceId: null, numericInput: '' },
 22→        });
 23→        return;
 24→      }
 25→
 26→      const part = project.parts.find((p) => p.id === intersection.partId);
 27→      if (!part) return;
 28→
 29→      const faceId = identifyFace(intersection.faceNormal);
 30→
 31→      editorDispatch({
 32→        type: 'UPDATE_TOOL_STATE',
 33→        payload: {
 34→          extruding: true,
 35→          sourcePart: part,
 36→          faceId,
 37→          startPoint: intersection.point,
 38→          faceNormal: intersection.faceNormal,
 39→          extrusionDistance: 0,
 40→          numericInput: '',
 41→        },
 42→      });
 43→    },
 44→
 45→    onPointerMove(intersection, e, toolState, viewport) {
 46→      if (!toolState.extruding || !toolState.startPoint || !toolState.faceNormal) return;
 47→
 48→      const currentPoint = intersection?.planePoint;
 49→      if (!currentPoint) return;
 50→
 51→      // Project mouse movement onto face normal axis
 52→      const fn = toolState.faceNormal;
 53→      const dx = currentPoint.x - toolState.startPoint.x;
 54→      const dy = currentPoint.y - toolState.startPoint.y;
 55→      const dz = currentPoint.z - toolState.startPoint.z;
 56→
 57→      // Dot product with face normal gives distance along normal
 58→      let distance = dx * fn.x + dy * fn.y + dz * fn.z;
 59→
 60→      if (snapEnabled) {
 61→        distance = snapToGrid(distance, SKETCH_GRID_MINOR);
 62→      }
 63→
 64→      editorDispatch({
 65→        type: 'UPDATE_TOOL_STATE',
 66→        payload: { extrusionDistance: distance },
 67→      });
 68→    },
 69→
 70→    onPointerUp(intersection, e, toolState, viewport) {
 71→      if (!toolState.extruding || !toolState.sourcePart || !toolState.faceId) return;
 72→
 73→      const distance = toolState.extrusionDistance || 0;
 74→      if (Math.abs(distance) < 1) {
 75→        // Too small - keep state for numeric input
 76→        return;
 77→      }
 78→
 79→      commitExtrusion(dispatch, editorDispatch, toolState.sourcePart, toolState.faceId, distance);
 80→    },
 81→
 82→    onKeyDown(e, toolState) {
 83→      if (!toolState.extruding && !toolState.sourcePart) return;
 84→
 85→      // Numeric input mode
 86→      if (e.key >= '0' && e.key <= '9') {
 87→        e.preventDefault();
 88→        editorDispatch({
 89→          type: 'UPDATE_TOOL_STATE',
 90→          payload: { numericInput: (toolState.numericInput || '') + e.key },
 91→        });
 92→        return;
 93→      }
 94→
 95→      if (e.key === '.' && !(toolState.numericInput || '').includes('.')) {
 96→        e.preventDefault();
 97→        editorDispatch({
 98→          type: 'UPDATE_TOOL_STATE',
 99→          payload: { numericInput: (toolState.numericInput || '') + '.' },
100→        });
101→        return;
102→      }
103→
104→      if (e.key === 'Backspace' && toolState.numericInput) {
105→        e.preventDefault();
106→        editorDispatch({
107→          type: 'UPDATE_TOOL_STATE',
108→          payload: { numericInput: toolState.numericInput.slice(0, -1) },
109→        });
110→        return;
111→      }
112→
113→      if (e.key === '-' && !(toolState.numericInput || '').includes('-')) {
114→        e.preventDefault();
115→        editorDispatch({
116→          type: 'UPDATE_TOOL_STATE',
117→          payload: { numericInput: '-' + (toolState.numericInput || '') },
118→        });
119→        return;
120→      }
121→
122→      if (e.key === 'Enter' && toolState.numericInput && toolState.sourcePart && toolState.faceId) {
123→        e.preventDefault();
124→        const distance = parseFloat(toolState.numericInput);
125→        if (!isNaN(distance) && Math.abs(distance) >= 1) {
126→          commitExtrusion(dispatch, editorDispatch, toolState.sourcePart, toolState.faceId, distance);
127→        }
128→        return;
129→      }
130→
131→      if (e.key === 'Escape') {
132→        editorDispatch({
133→          type: 'UPDATE_TOOL_STATE',
134→          payload: {
135→            extruding: false,
136→            sourcePart: null,
137→            faceId: null,
138→            startPoint: null,
139→            faceNormal: null,
140→            extrusionDistance: 0,
141→            numericInput: '',
142→          },
143→        });
144→      }
145→    },
146→
147→    getCursor(toolState) {
148→      if (toolState?.extruding) return 'ns-resize';
149→      return 'crosshair';
150→    },
151→  };
152→}
153→
154→function commitExtrusion(dispatch, editorDispatch, sourcePart, faceId, distance) {
155→  const result = computeExtrusionFromFace(sourcePart, faceId, distance);
156→  if (!result) return;
157→
158→  const part = createPanel(result.partOverrides);
159→  dispatch({ type: 'PART_ADD', part });
160→
161→  if (result.constraint) {
162→    const constraint = createConstraint({
163→      ...result.constraint,
164→      sourcePartId: part.id,
165→    });
166→    dispatch({ type: 'CONSTRAINT_ADD', constraint });
167→  }
168→
169→  editorDispatch({
170→    type: 'SET_STATUS_MESSAGE',
171→    message: `Extruded ${Math.round(Math.abs(distance))} mm from ${faceId} face`,
172→  });
173→
174→  editorDispatch({
175→    type: 'UPDATE_TOOL_STATE',
176→    payload: {
177→      extruding: false,
178→      sourcePart: null,
179→      faceId: null,
180→      startPoint: null,
181→      faceNormal: null,
182→      extrusionDistance: 0,
183→      numericInput: '',
184→    },
185→  });
186→}
