  1→import { useRef, useEffect, useCallback, useMemo, useState } from 'react';
  2→import * as THREE from 'three';
  3→import { useSketch } from '../app/SketchProvider';
  4→import { useSketchEditor } from '../app/SketchEditorProvider';
  5→import { buildSketchPreviewRoot } from './buildSketchPreview';
  6→import { getSketchInspection } from './sketchPreviewInspection';
  7→import { createPreviewViewport } from '@/three/viewer/createPreviewViewport';
  8→import { disposeScene } from '@/three/viewer/disposeScene';
  9→import { create3dHandler } from '../editor/handlers3d/index';
 10→import { createDrawingPlaneOverlay } from './DrawingPlaneOverlay';
 11→import { createExtrusionPreview } from './ExtrusionPreview';
 12→import { GROUND_PLANE } from '../domain/drawingPlane';
 13→import { SKETCH_TOOL_SHORTCUTS } from '../editor/tools';
 14→import CompassOverlay from '@/ui/CompassOverlay';
