105→/**
106→ * Map a Three.js face normal (approximate) to a canonical face ID.
107→ * Three.js coords: x=domain x, y=domain z, z=domain y
108→ */
109→export function identifyFace(threeNormal) {
110→  const ax = Math.abs(threeNormal.x);
111→  const ay = Math.abs(threeNormal.y);
112→  const az = Math.abs(threeNormal.z);
113→
114→  if (ay >= ax && ay >= az) {
115→    return threeNormal.y > 0 ? '+z' : '-z'; // Three.js Y = domain Z
116→  }
117→  if (ax >= ay && ax >= az) {
118→    return threeNormal.x > 0 ? '+x' : '-x';
119→  }
120→  return threeNormal.z > 0 ? '+y' : '-y'; // Three.js Z = domain Y
121→}
